ENDPOINT_BY_KEY = {spec.key.lower(): spec for spec in ENDPOINTS}
ENDPOINT_BY_PATH = {spec.path.lower().rstrip("/"): spec for spec in ENDPOINTS}

def get_endpoint(name: str) -> EndpointSpec:
    normalized = name.strip()
    if not normalized:
        raise KeyError("empty endpoint name")
    path_key = normalized.lower().rstrip("/")
    if path_key.startswith("/") and path_key in ENDPOINT_BY_PATH:
        return ENDPOINT_BY_PATH[path_key]
    key = normalized.strip("/").lower()
    if key in ENDPOINT_BY_KEY:
        return ENDPOINT_BY_KEY[key]
    if ("/" + key) in ENDPOINT_BY_PATH:
        return ENDPOINT_BY_PATH["/" + key]
    raise KeyError(f"unknown ArchersHub endpoint: {name}")
